class Solution {
public:
    vector<int> transformArray(vector<int>& nums) {
        int count_odd = 0;
        for (int num : nums) {
            if (num % 2 != 0) {
                count_odd++;
            }
        }
        int count_even = nums.size() - count_odd;
        vector<int> result(nums.size(), 0);
        for (int i = count_even; i < nums.size(); i++) {
            result[i] = 1;
        }
        return result;
    }
};
